import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom';
import { CCol, CForm, CButton, CFormLabel } from "@coreui/react";
import FormInput from 'src/utils/FormInput';
import Select from 'react-select';
import { permissionList } from 'src/utils/PermissionList';
import { createRole, getUserRoleById, updateUserRole } from 'src/components/services/RoleApi';
import GoBackComponent from 'src/utils/GoBackComponent';

const CommonRoleForm = (props) => {
    const { formType,updateId } = props;
    const [permissionsList,setPermissionsList] = useState([]);
    const [formData, setFormData] = useState({ title: "" });
    const [errors, setErrors] = useState({});
    const navigate = useNavigate();


    useEffect(() => {
        if(updateId){
            getUserRoleDetailsById(updateId);
        }
    }, [])

    const validateForm = (conflictMessage) => {
        let errors = {};
        let formIsValid = true;

        if (!formData.title || conflictMessage) {
            errors['title'] =  !formData.title ? "Please enter a title" : conflictMessage
            formIsValid = false;
        }
        if (permissionsList.length === 0) {
            errors['permission'] = "Please select al least one permission";
            formIsValid = false;
        }
        setErrors(errors);
        setTimeout(() => {
            setErrors({});
        }, 2000);

        return formIsValid;
    };

    const handleFormSubmit = async() => {

        if (validateForm()) {
            let postData = {name: formData?.title, permissions: permissionsList && permissionsList.map(data => {return data?.value}), ...(updateId && { id: updateId })};
            let response = updateId ? await updateUserRole(postData) : await createRole(postData);
            if(response?.code === 201 || response?.code === 202){
                navigate('/role');
            }else if (response?.code === 409){
                validateForm(response?.message)
            }
        }
    };

    const handleChangeTitle = (event) => {
        setFormData({ ...formData, [event.target.name]: event.target.value.trimStart().replace(/  +/g, ' ') });
    };

    const handleChangePermission = (permission) => {
        setPermissionsList(permission);
    };

    const getUserRoleDetailsById = async (id) => {
        let response = await getUserRoleById(id);
        if(response?.code === 200){
            let pageData = response?.results;
            setFormData({title: pageData?.name})
            setPermissionsList(pageData && pageData.permissions && pageData.permissions.map(item => ({value: item, label: item.replace(/_/g, ' ')})))
        }
    };

    return (
        <>
            <GoBackComponent goBackData={"role"} />
            <div className='customContainer'>
                <CForm className="row g-3">
                    <CCol md={12}>
                        <FormInput
                            value={formData.title}
                            label={"Title"}
                            required
                            name={"title"}
                            onChange={handleChangeTitle}
                            error={errors['title']}
                        />
                    </CCol>

                    <CCol md={12}>
                        <CFormLabel htmlFor='exampleFormControlTextarea1'>Select Permission <span className='text-danger'>*</span></CFormLabel>
                        <Select
                            isMulti
                            value={permissionsList}
                            options={permissionList && permissionList.map(item => ({value: item, label: item.replace(/_/g, ' ')}))}
                            onChange={handleChangePermission}
                            placeholder={"Start typing"}
                            closeMenuOnSelect={false}
                            classNamePrefix="select"
                            styles={{
                                control: styles => ({ ...styles, borderColor: errors["permission"] && 'red', height: '50px' }),
                                option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                    const color = '#03a68059';
                                    return {
                                        ...styles,
                                        backgroundColor: isDisabled
                                            ? null
                                            : isSelected
                                                ? '#03a68059'
                                                : isFocused
                                                    ? '#03a68059'
                                                    : null,
                                        color: isDisabled
                                            ? '#ccc'
                                            : isSelected
                                                ? color > 2
                                                    ? '#00374d'
                                                    : '#00374d'
                                                : data.color,
                                        cursor: isDisabled ? 'not-allowed' : 'default',

                                        ':active': {
                                            ...styles[':active'],
                                            backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                                        },
                                    };
                                },
                            }}
                        />
                        {errors["permission"] && <span style={{ color: "red" }}>{errors["permission"]}</span>}
                    </CCol>
                    <CCol md={12}>
                        <CButton color="primary" onClick={handleFormSubmit} className="d-block">
                            {formType === "CREATE" ? "Create" : "Update"}
                        </CButton>
                    </CCol>
                </CForm>
            </div>
        </>
    )
}

export default CommonRoleForm;
